const express = require('express');
const bodyParser = require('body-parser');
require('dotenv').config(); // Load environment variables from .env file (if exists)
var OpenAI = require("openai");
OpenAI.apiKey = process.env.OPEN_API_KEY; 
// You can set the API key as an environmental variable or hard-code it here for testing purposes, but not in a production environment due to security concerns about exposing your secret keys publicly. Use dotenv package if you want secure way of handling this issue (install with npm install --save dotenv). 
const app = express(); // Initialize the application using Express framework  
app.use(bodyParser());// Parse incoming requests data as JSON and make it available through req.body in your routes   
    
let previousPrompts=[];     
        
async function generateCodeFromLanguageModel (prompt) {  // Function to call the language model for code generation  
        let response = await OpenAI.generateText( prompt,{
            temperature:0 ,// This controls randomness in the output strings from our AI models   
             maxTokens :256 });    
         return JSON.parse('{"text":"'+response+'"}');  // Returning a json object with text property containing generated code  
 }     
         
app.post('/generate', async (req, res) => {       // Route to handle POST requests at /generate URL   
     let prompt = req.body;        if(!prompt){         return res.status(400).send('No Prompt provided');}  else   previousPrompts .push({"time":new Date(), "text":req.body});      // Save the time and text of this request in our history array      
     let generatedCode;          try {           if (previousPrompts.length > 3)         await generateCodeFromLanguageModel(previousPrompts[0].text);        } catch (error){            console .log ("Error: ", error );}      // If we have more than 2 previous prompt, use the first one for generation      
     if (!generatedCode && !/^\w+(\.\w+)?$/.test(prompt)) {         return res.status(400).send('Invalid input'); } else        generatedCode = await generateCodeFromLanguageModel (req.body);      // Generate code from the prompt received in POST request      
     if (!generatedCode)  throw new Error ('Error generating response, please try again later!') ;// If there was an error while trying to get a result send back with status of '500' and message as "An internal server issue occurred. Please wait for some time then retry."     
     res .status(201).send (generatedCode); // Send the generated code in response      
 }); 
         app.listen('3000', () => { console .log ('Server started on port: ' + 3000)} );// Start server at specified or defaulted ports    } catch (error) {console. log ("Error occurred while starting up the application", error);} })   // Catch any errors that occur during startup and print them to logs